class TestFreezeCard:
    """Happy-path and edge-cases for freeze."""

    def test_freeze_active_card_returns_frozen_status(
        self, card_service, active_card
    ):
        result = card_service.freeze_card(
            active_card.card_id, active_card.owner_customer_id
        )
        assert result.status == CardStatus.FROZEN

    def test_freeze_active_card_sets_freeze_timestamp(
        self, card_service, active_card
    ):
        before = datetime.utcnow()
        result = card_service.freeze_card(
            active_card.card_id, active_card.owner_customer_id
        )
        after = datetime.utcnow()
        assert result.freeze_timestamp is not None
        assert before <= result.freeze_timestamp <= after

    def test_freeze_is_instant_within_one_second(
        self, card_service, active_card
    ):
        """The freeze operation completes and is persisted within 1 second."""
        t0 = datetime.utcnow()
        card_service.freeze_card(
            active_card.card_id, active_card.owner_customer_id
        )
        elapsed = (datetime.utcnow() - t0).total_seconds()
        assert elapsed < 1.0, f"Freeze took {elapsed:.3f}s – expected < 1s"

    def test_freeze_persists_to_repository(
        self, card_service, card_repo, active_card
    ):
        card_service.freeze_card(
            active_card.card_id, active_card.owner_customer_id
        )
        persisted = card_repo.get(active_card.card_id)
        assert persisted.status == CardStatus.FROZEN

    def test_freeze_already_frozen_card_raises(
        self, card_service, frozen_card
    ):
        with pytest.raises(CardAlreadyInStateError):
            card_service.freeze_card(
                frozen_card.card_id, frozen_card.owner_customer_id
            )

    def test_freeze_nonexistent_card_raises(self, card_service):
        with pytest.raises(CardNotFoundError):
            card_service.freeze_card("nonexistent-card", "customer-001")

    def test_freeze_does_not_alter_balance(
        self, card_service, active_card
    ):
        original_balance = active_card.balance
        result = card_service.freeze_card(
            active_card.card_id, active_card.owner_customer_id
        )
        assert result.balance == original_balance


