        self, card_service, auth_logger, frozen_card
    ):
        card_service.authorize_transaction(
            frozen_card.card_id, Decimal("50.00"), "merchant-A"
        )
        auth_logger.log.assert_called_once_with(
            frozen_card.card_id, "DECLINED_FROZEN", Decimal("50.00"), "merchant-A"
        )

    @pytest.mark.parametrize(
        "amount",
        [
            Decimal("1.00"),
            Decimal("10.00"),
            Decimal("100.00"),
            Decimal("500.00"),
            Decimal("1000.00"),
        ],
    )
    def test_frozen_card_rejects_various_amounts(
        self, card_service, frozen_card, amount
    ):
        result = card_service.authorize_transaction(
            frozen_card.card_id, amount, "merchant-B"
        )
        assert result == AuthorizationResult.DECLINED_FROZEN

    def test_active_card_can_transact_after_unfreeze(
        self, card_service, frozen_card
    ):
        card_service.unfreeze_card(
            frozen_card.card_id, frozen_card.owner_customer_id
        )
        result = card_service.authorize_transaction(
            frozen_card.card_id, Decimal("50.00"), "merchant-C"
        )
        assert result == AuthorizationResult.APPROVED

    def test_unfrozen_card_rejected_while_frozen_then_approved(
        self, card_service, active_card
    ):
        # Approve first
        r1 = card_service.authorize_transaction(
            active_card.card_id, Decimal("50.00"), "merchant-D"
        )
        assert r1 == AuthorizationResult.APPROVED

        # Freeze
        card_service.freeze_card(
            active_card.card_id, active_card.owner_customer_id
        )

        # Reject
        r2 = card_service.authorize_transaction(
            active_card.card_id, Decimal("50.00"), "merchant-D"
        )
        assert r2 == AuthorizationResult.DECLINED_FROZEN

        # Unfreeze
        card_service.unfreeze_card(
            active_card.card_id, active_card.owner_customer_id
        )

        # Approve again
        r3 = card_service.authorize_transaction(
            active_card.card_id, Decimal("50.00"), "merchant-D"
        )
        assert r3 == AuthorizationResult.APPROVED


